import (
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
	"github.com/openmeterio/openmeter/pkg/framework/transaction"
)

func (m *connector) NewMutation(ctx context.Context, ownerID models.NamespacedID) error {
	ctx, span := m.Tracer.Start(ctx, "credit.NewMutation", cTrace.WithOwner(ownerID))
	defer span.End()
	_, err := transaction.Run(ctx, m.GrantRepo, func(ctx context.Context) (*interface{}, error) {
		tx, err := entutils.GetDriverFromContext(ctx)
		if err != nil { return nil, err }
		if err := m.OwnerConnector.LockOwnerForTx(ctx, ownerID, true); err != nil { return nil, err }
		return nil, m.GrantRepo.WithTx(ctx, tx).SomeWrite(ctx, ownerID)
	})
	return err
}

import (
	"context"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
	entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
	"github.com/openmeterio/openmeter/pkg/models"
)

func (a *adapter) CreateFoo(ctx context.Context, params currencies.CreateFooInput) (currencies.Foo, error) {
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) (currencies.Foo, error) {
		row, err := tx.db.Foo.Create().SetNamespace(params.Namespace).SetCode(params.Code).Save(ctx)
		if err != nil {
			if entdb.IsConstraintError(err) {
				return currencies.Foo{}, models.NewGenericConflictError(err)
			}
			return currencies.Foo{}, err
		}
		return mapFooFromDB(row), nil
	})
}
